def removeInvalidParentheses(s: str) -> List[str]:
    stack = []
    result = []
    for char in s:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if len(stack) == 0:
                return []
            stack.pop()
    if len(stack) != 0:
        return []
    for char in s:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if len(stack) == 0:
                return []
            result.append(stack.pop())
    return result

